1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: Step[];
6	};
7	
8	const PROCESSING_FEE = 5;
9	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
10	const ITEM_BASE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const COMPONENT_BLOCK_SIZE = 3;
20	const COMPONENT_BLOCK_BASE = 60;
21	
22	const itemBase = (item: Item): number => ITEM_BASE[item.type];
23	
24	const isComponentBlock = (items: Item[]): boolean =>
25	  items.length === COMPONENT_BLOCK_SIZE &&
26	  items.every((item) => item.type === items[0].type);
27	
28	const sumItemBases = (items: Item[]): number =>
29	  items.reduce((sum, item) => sum + itemBase(item), 0);
30	
31	const calculatePolicyBase = (items: Item[]): number =>
32	  isComponentBlock(items) ? COMPONENT_BLOCK_BASE : sumItemBases(items);
33	
34	const roundUpInMHPCOsFavor = (amount: number): number => Math.ceil(amount);
35	
36	const quotePremium = ({ items }: Step): number => {
37	  const policyBase = calculatePolicyBase(items);
38	  const firstContractSurcharge = policyBase * FIRST_CONTRACT_SURCHARGE_RATE;
39	  const rawPremium = policyBase + firstContractSurcharge + PROCESSING_FEE;
40	  return roundUpInMHPCOsFavor(rawPremium);
41	};
42	
43	export const runScenario = ({ steps }: Scenario): { results: unknown[] } => {
44	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
45	  return { results };
46	};
